svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var ringLayer = document.getElementById('ring-layer');
    var edgeLayer = document.getElementById('edge-layer');
    var nodeLayer = document.getElementById('node-layer');
    var legendRoot = document.getElementById('legend-root');
    var tip = document.getElementById('tip');
    var plotL = 68;
    var plotR = 850;
    var plotT = 100;
    var plotB = 500;
    var cx = (plotL + plotR) / 2;
    var cy = (plotT + plotB) / 2;
    var ringR = 185;
    var labelR = ringR + 26;
    var gapDeg = 14;
    var plotShiftX = 0;

    var nodes = [
      { id:'web-app', label:'Web App', cluster:1 },
      { id:'mobile', label:'Mobile', cluster:1 },
      { id:'cdn', label:'CDN', cluster:1 },
      { id:'api-gw', label:'API GW', cluster:2 },
      { id:'user-svc', label:'User Svc', cluster:2 },
      { id:'order-svc', label:'Order Svc', cluster:2 },
      { id:'notify', label:'Notify', cluster:2 },
      { id:'postgres', label:'Postgres', cluster:3 },
      { id:'redis', label:'Redis', cluster:3 },
      { id:'kafka', label:'Kafka', cluster:3 },
      { id:'analytics', label:'Analytics', cluster:3 },
      { id:'k8s', label:'K8s', cluster:4 },
      { id:'monitor', label:'Monitor', cluster:4 },
      { id:'cicd', label:'CI/CD', cluster:4 },
      { id:'auth-svc', label:'Auth Svc', cluster:5 },
      { id:'oauth', label:'OAuth', cluster:5 }
    ];

    var edges = [
      { a:'web-app', b:'cdn' },
      { a:'mobile', b:'cdn' },
      { a:'cdn', b:'api-gw' },
      { a:'web-app', b:'api-gw' },
      { a:'api-gw', b:'user-svc' },
      { a:'api-gw', b:'order-svc' },
      { a:'order-svc', b:'notify' },
      { a:'user-svc', b:'notify' },
      { a:'user-svc', b:'postgres' },
      { a:'order-svc', b:'postgres' },
      { a:'user-svc', b:'redis' },
      { a:'order-svc', b:'redis' },
      { a:'notify', b:'kafka' },
      { a:'api-gw', b:'kafka' },
      { a:'kafka', b:'analytics' },
      { a:'postgres', b:'analytics' },
      { a:'auth-svc', b:'api-gw' },
      { a:'auth-svc', b:'oauth' },
      { a:'oauth', b:'k8s' },
      { a:'k8s', b:'api-gw' },
      { a:'k8s', b:'postgres' },
      { a:'k8s', b:'monitor' },
      { a:'cicd', b:'k8s' },
      { a:'monitor', b:'analytics' }
    ];

    var clusterNames = {
      1: 'Frontend',
      2: 'Backend',
      3: 'Data',
      4: 'Infra',
      5: 'Auth'
    };
    var clusterItems = [
      { cls: 'series-1', label: 'Frontend', value: '3 nodes' },
      { cls: 'series-2', label: 'Backend', value: '4 nodes' },
      { cls: 'series-3', label: 'Data', value: '4 nodes' },
      { cls: 'series-4', label: 'Infra', value: '3 nodes' },
      { cls: 'series-5', label: 'Auth', value: '2 nodes' }
    ];

    var byId = {};
    var nodeItems = [];
    var edgeItems = [];
    var revealNodes = [];
    var revealDelays = [];
    var totalEdgeWindow;
    var totalNodeWindow;

    nodes.forEach(function (node) {
      node.neighbours = [];
      node.edgeEls = [];
      byId[node.id] = node;
    });

    edges.forEach(function (edge) {
      byId[edge.a].neighbours.push(edge.b);
      byId[edge.b].neighbours.push(edge.a);
    });

    nodes.forEach(function (node) {
      node.r = 11 + Math.min(node.neighbours.length - 1, 5) * 2.2;
    });

    (function layoutNodes() {
      var totalGapDeg = 5 * gapDeg;
      var nodeArcDeg = 360 - totalGapDeg;
      var degPerNode = nodeArcDeg / nodes.length;
      var angleDeg = -90 - (nodeArcDeg / 2);
      var prevCluster = null;

      nodes.forEach(function (node) {
        if (prevCluster !== null && node.cluster !== prevCluster) angleDeg += gapDeg;
        node.angle = angleDeg + degPerNode / 2;
        angleDeg += degPerNode;
        prevCluster = node.cluster;

        var rad = node.angle * Math.PI / 180;
        node.x = cx + ringR * Math.cos(rad);
        node.y = cy + ringR * Math.sin(rad);
        node.lx = cx + labelR * Math.cos(rad);
        node.ly = cy + labelR * Math.sin(rad);
        node.anchor = Math.cos(rad) > 0.1 ? 'start' : (Math.cos(rad) < -0.1 ? 'end' : 'middle');
      });
    }());

    ringLayer.appendChild(ctx.el('circle', {
      cx: cx,
      cy: cy,
      r: ringR,
      'class': 'ring-guide'
    }));
    revealNodes.push(ringLayer.firstChild);
    revealDelays.push(0);

    totalEdgeWindow = Math.min(1.2, Math.max(0.6, edges.length * 0.04));
    edges.forEach(function (edge, index) {
      var fromNode = byId[edge.a];
      var toNode = byId[edge.b];
      var midX = (fromNode.x + toNode.x) / 2;
      var midY = (fromNode.y + toNode.y) / 2;
      var ctrlX = midX + (cx - midX) * 0.42;
      var ctrlY = midY + (cy - midY) * 0.42;
      var edgeEl = ctx.el('path', {
        d: 'M' + fromNode.x + ',' + fromNode.y + ' Q' + ctrlX + ',' + ctrlY + ' ' + toNode.x + ',' + toNode.y,
        'class': 'edge series-' + fromNode.cluster + ' use-series-stroke',
        'data-a': edge.a,
        'data-b': edge.b
      });
      edgeLayer.appendChild(edgeEl);
      fromNode.edgeEls.push(edgeEl);
      toNode.edgeEls.push(edgeEl);
      edgeItems.push(edgeEl);
      revealNodes.push(edgeEl);
      revealDelays.push(0.08 + ctx.getStaggerDelay(index, edges.length, totalEdgeWindow, svgEl));
    });

    totalNodeWindow = Math.min(1.0, Math.max(0.4, nodes.length * 0.04));
    nodes.forEach(function (node, index) {
      var nodeEl = ctx.el('g', {
        id: 'ng-' + node.id,
        'class': 'node-g',
        'data-node-id': node.id,
        'data-item-cx': String(node.x),
        'data-item-top': String(node.y)
      });
      var circleEl = ctx.el('circle', {
        cx: node.x,
        cy: node.y,
        r: node.r,
        'class': 'node-circle series-' + node.cluster + ' use-series-stroke'
      });
      var labelEl = ctx.el('text', {
        x: node.lx,
        y: node.ly + 3.5,
        'text-anchor': node.anchor,
        'class': 'node-lbl'
      });
      labelEl.textContent = node.label;
      nodeEl.appendChild(circleEl);
      nodeEl.appendChild(labelEl);
      nodeLayer.appendChild(nodeEl);
      node._el = nodeEl;
      nodeItems.push(nodeEl);
      revealNodes.push(nodeEl);
      revealDelays.push(0.48 + ctx.getStaggerDelay(index, nodes.length, totalNodeWindow, svgEl));
    });

    ctx.initRevealSequence(revealNodes, {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: revealDelays
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      items: clusterItems
    });

    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      slotLeft: 0,
      legendGap: 24,
      clamp: true
    }).shiftX || 0;

    var connectedHover = ctx.initConnectedHover(dataLayerEl, nodeItems, {
      allNodes: nodeItems,
      allEdges: edgeItems,
      getRelatedItems: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        return node ? node.neighbours.map(function (id) {
          var other = byId[id];
          return other && other._el ? other._el : null;
        }).filter(Boolean) : [];
      },
      getRelatedEdges: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        return node ? node.edgeEls : [];
      }
    });

    ctx.initStandardTooltip(dataLayerEl, nodeItems, {
      tip: tip,
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: (Number(itemEl.getAttribute('data-item-cx')) || 0) + plotShiftX,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        var degree = node ? node.neighbours.length : 0;
        return {
          primary: node ? node.label : '',
          label: clusterNames[node ? node.cluster : 1] || '',
          meta: degree + ' connection' + (degree === 1 ? '' : 's')
        };
      },
      onActivate: function (itemEl) {
        connectedHover.activate(itemEl);
      },
      onDeactivate: function () {
        connectedHover.clear();
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: revealDelays,
      duration: 0.8,
      buffer: 0.1
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
